6778   // through all users we can easily track, and then check whether any of those
6779   // users are provable UB and must execute before out exiting block might
6780   // exit.
6781 
6782   // The set of all recursive users we've visited (which are assumed to all be
6783   // poison because of said visit)
6784   SmallSet<const Value *, 16> KnownPoison;
6785   SmallVector<const Instruction*, 16> Worklist;
6786   Worklist.push_back(Root);
6787   while (!Worklist.empty()) {
6788     const Instruction *I = Worklist.pop_back_val();
6789 
6790     // If we know this must trigger UB on a path leading our target.
6791     if (mustTriggerUB(I, KnownPoison) && DT->dominates(I, OnPathTo))
6792       return true;
